import type {
  HistogramChartConfiguration,
  HistogramChartYAxisProps,
} from '../../../histogram/types/histogram-props.js';
import type { MappedPositionedAxes, YAxisProps } from '../types/slots.js';

/**
 * Maps a Histogram y-axis (left or right) into the partial XYChart-compatible
 * y-axis representation used by `buildYAxisProps`.
 */
export const mapYAxisToInternal = (
  yAxis: HistogramChartYAxisProps | undefined,
  position: 'left' | 'right',
): Omit<YAxisProps, 'id'> | undefined => {
  if (!yAxis) {
    return undefined;
  }
  // Strip the histogram-specific `scale` key; convert `scale` → XYChart axis
  // `type`. The `position` is supplied explicitly by the caller.
  const { position: _position, scale, ...rest } = yAxis;
  return {
    ...rest,
    type: scale === 'log' ? 'log' : 'numerical',
    position,
  };
};

/**
 * Builds the `MappedPositionedAxes` shape expected by `buildYAxisProps`
 * from a fully resolved `HistogramChartConfiguration`.
 */
export const buildYAxesConfigFromConfig = (
  config: HistogramChartConfiguration,
): MappedPositionedAxes => {
  const left = mapYAxisToInternal(config.yAxis.left, 'left');
  const right = mapYAxisToInternal(config.yAxis.right, 'right');
  const result: MappedPositionedAxes = {};
  if (left) {
    result.left = left;
  }
  if (right) {
    result.right = right;
  }
  return result;
};
